using Common.Geometry;
using Script;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Diagnostics;
using System;
using System.IO;
using System.Linq;

namespace Plugin.ScriptCSharp
{
    public class ReadData : IScript
    {
        public ConcurrentDictionary<string, object> Execute(ConcurrentDictionary<string, object> parameters)
        {
            ConcurrentDictionary<string, object> result = new ConcurrentDictionary<string, object>();
            var path =(string) parameters["上传MES.数据文件路径"];
            if (!path.IsNullOrEmpty())
            {
                if (File.Exists(path))
                {
                    var power= XMLProcess.Read(path, "/Datas/最大功率").To<double>();
                    result.TryAdd("上传MES.激光功率", power);
                    result.TryAdd("运行结果", true);
                }
                else
                {
                    result.TryAdd("返回消息", $"文件[{path}]不存在!");
                }
            }
            else
            {
                string retMsg = parameters.Select(s => $"{s.Key}:{s.Value}").ToStringJoin(";");
                result.TryAdd("返回消息", $"输入参数转换错误:{retMsg}");
            }
            result.TryAdd("运行结果", false);
            return result;
        }
    }
}

using Common.Geometry;
using Script;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Diagnostics;
using System;
using System.IO;
using System.Linq;

namespace Plugin.ScriptCSharp
{
    public class Script2PointSlopeComparison : IScript
    {
        public ConcurrentDictionary<string, object> Execute(ConcurrentDictionary<string, object> parameters)
        {
            ConcurrentDictionary<string, object> result = new ConcurrentDictionary<string, object>();
            var dwdit = parameters["全局.定位坐标"] as Dictionary<string, Point>;
            var jdzdpc = parameters["全局.极柱角度最大偏差"].ToString().To<double>();
            bool b = false;
            List<double> slopes = new List<double>();
            if (dwdit.IsNotNullOrEmpty() && jdzdpc != 0)
            {
                var no = dwdit.Keys.ToArray()[dwdit.Count - 1].To<int>();
                if (no % 2 == 0)
                {
                    for (int i = 0; i < no / 2; i++)
                    {
                        double sp = 0;
                        sp = Point.Get2PointAngle(dwdit[(i * 2 + 1).ToString()], dwdit[(i * 2 + 2).ToString()]);
                        sp = Math.Abs(sp);
                        slopes.Add(sp);
                    }
                    var ms = slopes.GetMidItems(1, 1);
                    var avg = ms.Average();
                    var min = slopes.Min();
                    var max = slopes.Max();
                    if ((max - avg) > jdzdpc)
                    {
                        result.TryAdd("返回消息", $"电芯[{slopes.IndexOf(max) + 1}]极柱定位角度[{max}]相差平均值[{avg}]{max - avg}度,超出全局.极柱角度最大偏差[{jdzdpc}]限制，所有电芯极柱定位角度:{slopes.ConvertToString()}");
                    }
                    else if ((avg - min) > jdzdpc)
                    {
                        result.TryAdd("返回消息", $"电芯[{slopes.IndexOf(min) + 1}]极柱定位角度[{min}]相差平均值[{avg}]{avg - min}度,超出全局.极柱角度最大偏差[{jdzdpc}]限制，所有电芯极柱定位角度:{slopes.ConvertToString()}");
                    }
                    else
                    {
                        result.TryAdd("返回消息", $"所有电芯极柱定位角度:{slopes.ConvertToString()}");
                        b = true;
                    }
                }
            }
            else
            {
                string retMsg = parameters.ConvertToString();
                result.TryAdd("返回消息", $"转换值错误:{retMsg}");
            }
            result.TryAdd("运行结果", b);
            return result;
        }
    }
}

using Common.Geometry;
using Script;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Diagnostics;
using System;
using System.IO;
using System.Linq;

namespace Plugin.ScriptCSharp
{
    public class Script2PointComparison : IScript
    {
        public ConcurrentDictionary<string, object> Execute(ConcurrentDictionary<string, object> parameters)
        {
            ConcurrentDictionary<string, object> result = new ConcurrentDictionary<string, object>();
            var dwdit = parameters["全局.定位坐标"] as Dictionary<string, Point>;
            var zxjj = parameters["全局.极柱中心间距"].ToString().To<double>();
            var zdjz = parameters["全局.极柱最大差值"].ToString().To<double>();
            var wzbh = parameters["电芯拍照.位置编号"].ToString().To<short>();
            bool b = false;
            if (dwdit.IsNotNullOrEmpty() && zxjj != 0 && zdjz != 0 && wzbh != 0)
            {
                if (wzbh % 2 == 0)
                {
                    var p1 = dwdit[wzbh.ToString()];
                    var p2 = dwdit[(wzbh - 1).ToString()];
                    var jl = Point.CalculateDistance(p1, p2);
                    var jlcz = Math.Abs(jl - zxjj);
                    b = jlcz <= zdjz;
                    if (!b)
                    {
                        result.TryAdd("返回消息", $"焊点[{wzbh - 1}]、[{wzbh}]极柱中心间距异常:[{jl}]偏出标准间距[{zxjj}]{jlcz}，大于设定极柱最大差值[{zdjz}]");
                    }
                    else
                    {
                        result.TryAdd("返回消息", $"焊点[{wzbh - 1}]、[{wzbh}]极柱中心间距[{jlcz}]");
                    }
                }
                else
                {
                    b = true;
                }
            }
            else
            {
                string retMsg = parameters.ConvertToString();
                result.TryAdd("返回消息", $"转换值错误:{retMsg}");
            }
            result.TryAdd("运行结果", b);
            result.TryAdd("电芯拍照.写入结果", b?1:2);
            return result;
        }
    }
}

using Common.Geometry;
using Common;
using Script;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Diagnostics;
using System;
using System.IO;
using System.Linq;
namespace Plugin.ScriptCSharp
{
  public class ScriptToXYList : IScript
    {
        public ConcurrentDictionary<string, object> Execute(ConcurrentDictionary<string, object> parameters)
        {
            ConcurrentDictionary<string, object> result = new ConcurrentDictionary<string, object>();
            var szdit = parameters["写三轴坐标.加工坐标表"] as Dictionary<string, Point>;
            var qxxtdit = parameters["全局.标准Mark点坐标表"] as Dictionary<string, Point>;
            var xtdit = parameters["全局.定位Mark点坐标表"] as Dictionary<string, Point>;
            var jgpc= (double) parameters["全局.Mark点间距偏差"] ;

            int cellnum = (int)parameters["全局.加工点数"];
            short i = 0;
            bool b = false;
            if (!szdit.IsNullOrEmpty()&& !qxxtdit.IsNullOrEmpty()&&!xtdit.IsNullOrEmpty() && cellnum != 0)
            {
                if (qxxtdit.Count==3&& xtdit.Count==3)
                {
                    var qxjg1= Point.CalculateDistance(qxxtdit["1"], qxxtdit["2"]);
                    var qxjg2 = Point.CalculateDistance(qxxtdit["2"], qxxtdit["3"]);
                    var qxjg3 = Point.CalculateDistance(qxxtdit["1"], qxxtdit["3"]);
                    var xtjg1 = Point.CalculateDistance(xtdit["1"], xtdit["2"]);
                    var xtjg2 = Point.CalculateDistance(xtdit["2"], xtdit["3"]);
                    var xtjg3 = Point.CalculateDistance(xtdit["1"], xtdit["3"]);
                    var cz1= Math.Abs(qxjg1 - xtjg1);
                    var cz2 = Math.Abs(qxjg2 - xtjg2);
                    var cz3 = Math.Abs(qxjg3 - xtjg3);
                    if (cz1 <= jgpc && cz2 <= jgpc && cz3 <= jgpc)
                    {
                        if (szdit.Count == cellnum)
                        {
                            List<int> xs = new List<int>();
                            List<int> ys = new List<int>();
                            bool fb = true;
                            for (int j = 1; j <= cellnum; j++)
                            {
                                string key = j.ToString();
                                if (szdit.ContainsKey(key))
                                {
                                    xs.Add((szdit[key].X * 200).To<int>());
                                    ys.Add((szdit[key].Y * 200).To<int>());
                                }
                                else
                                {
                                    result.TryAdd("返回消息", $"全局.焊接坐标表字典中不包含序号{key}");
                                    fb = false;
                                    break;
                                }
                            }
                            if (fb)
                            {
                                result.TryAdd("写三轴坐标.三轴X组", xs);
                                result.TryAdd("写三轴坐标.三轴Y组", ys);
                                b = true;
                            }

                        }
                        else
                        {
                            result.TryAdd("返回消息", $"写三轴坐标.加工坐标表的长度不等于{cellnum}:{szdit.Count}");
                        }
                    }
                    else
                    {
                        result.TryAdd("返回消息", $"当前Mark点对比标准Mark点间距大于设定值[{jgpc}]:{cz1}、{cz2}、{cz3}");
                    }

                }
                else
                {
                    result.TryAdd("返回消息", $"全局.标准Mark坐标表或全局.定位Mark表集合的数量不为3:[{qxxtdit.Count}]、[{xtdit.Count}]");
                }
            }
            else
            {
                string retMsg = parameters.ConvertToString();
                result.TryAdd("返回消息", $"转换值错误:{retMsg}");
            }
            i = (short)(b ? 1 : 2);
            result.TryAdd("写三轴坐标.PLC写入结果", i);
            result.TryAdd("运行结果", b);
            return result;
        }
    }

}
